customCSS:
/* Ocean Depths - Deep Blue */
@import url('https://fonts.googleapis.com/css2?family=Quicksand:wght@400;500;600;700&family=Nunito:wght@300;400;600&family=Fira+Code&display=swap');

.cyber-glow {
  background: 
    radial-gradient(ellipse 800px 500px at 50% 100%, rgba(48, 200, 232, 0.22), transparent),
    radial-gradient(ellipse 600px 400px at 20% 50%, rgba(32, 128, 204, 0.15), transparent),
    radial-gradient(ellipse 500px 300px at 80% 30%, rgba(48, 208, 160, 0.10), transparent);
}

.stat-card {
  border: 1px solid rgba(48, 200, 232, 0.12);
  backdrop-filter: blur(8px);
}

.stat-card::before {
  background: linear-gradient(90deg, #30d0a0, #30c8e8, #2080cc);
  height: 2px;
}

.stat-card:hover {
  border-color: rgba(48, 200, 232, 0.28);
  box-shadow: 0 4px 30px rgba(48, 200, 232, 0.12);
}

.stat-value {
  text-shadow: 0 0 18px currentColor;
}

.celebration-title {
  background: linear-gradient(135deg, #30c8e8, #30d0a0);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
}

.miner-card, .health-card, .lifetime-card {
  border: 1px solid rgba(48, 200, 232, 0.08);
}

.miner-card:hover {
  border-color: rgba(48, 208, 160, 0.2);
}
